// دالة البحث بأي لغة
export function searchCity(query: string, lang: 'en'|'ar'|'fr'|'es' = 'en'): City[] {
  const q = query.toLowerCase().trim();
  return WORLD_CITIES.filter(c =>
    c.iata.toLowerCase().includes(q) ||
    c.en.toLowerCase().includes(q) ||
    c.ar.includes(query) ||
    c.fr.toLowerCase().includes(q) ||
    c.es.toLowerCase().includes(q) ||
    c.country.toLowerCase().includes(q)
  ).slice(0, 10);
}

// IATA Record للاستخدام السريع
export const IATA_MAP: Record<string, string> = {};
WORLD_CITIES.forEach(c => {
  IATA_MAP[c.en.toLowerCase()] = c.iata;
  IATA_MAP[c.ar] = c.iata;
  IATA_MAP[c.fr.toLowerCase()] = c.iata;
  IATA_MAP[c.es.toLowerCase()] = c.iata;
  IATA_MAP[c.iata.toLowerCase()] = c.iata;
});